#C:/Users/user1/OneDrive/文件/card.code/app.R
library(shiny)
library(readxl)
library(DT)

# ====== 1. 安全隨機函數 ======
resample <- function(x, ...) {
  if (length(x) <= 1) x else sample(x, ...)
}

# ====== 2. CSS 樣式 (完全保留原始設定) ======
style <- "
  .flashcard-container { display: flex; justify-content: center; align-items: center; height: 620px; margin-bottom: 20px; width: 100%; }
  .flashcard-btn { width: 100%; max-width: 800px; height: 600px; background-color: #ffffff; border: 2px solid #dee2e6; border-radius: 20px; box-shadow: 0 6px 12px rgba(0,0,0,0.1); padding: 0; display: flex; flex-direction: column; overflow: hidden; }
  .card-status-hint { font-size: 13px; font-weight: bold; color: #aaa; padding: 15px 0 5px 0; text-transform: uppercase; letter-spacing: 1.5px; text-align: center; width: 100%; border-bottom: 1px solid #f8f9fa; flex-shrink: 0; background: white;}
  .card-content-wrapper { flex: 1; display: flex; flex-direction: column; align-items: center; overflow-y: auto; width: 100%; padding: 0 45px; -webkit-overflow-scrolling: touch;  max-height: 580px;
    font-size: 20px;    font-weight: bold;    line-height: 1.5;    white-space: pre-wrap;     word-wrap: break-word;}
  .inner-content { margin: auto 0; width: 100%; text-align: left; padding: 30px 0; font-size: 15px; font-weight: bold; line-height: 1.6; white-space: pre-wrap; word-wrap: break-word; color: inherit;
    min-height: min-content; }
  .btn-group-container { display: flex; justify-content: center; gap: 20px; margin-top: 10px; }
  .status-btn { width: 100%; max-width: 200px; font-size: 16px; padding: 12px; border-radius: 10px; font-weight: bold; }
  .control-panel { margin-top: 20px; padding: 20px; background-color: #f8f9fa; border-radius: 15px; border: 1px solid #eee; }
"

# ====== 3. UI 介面 ======
ui <- fluidPage(
  tags$head(tags$style(HTML(style))),
  titlePanel("Flashcards - 錯題記錄版"),
  
  tabsetPanel(
    tabPanel("主學習模式",
             br(),
             div(class = "control-panel",
                 fluidRow(
                   column(6, fileInput("upload_file", "📁 步驟 1：載入新題庫 (Excel)", accept = ".xlsx")),
                   column(6, fileInput("load_wrong", "📂 載入之前的錯題檔 (.csv)", accept = ".csv"))
                 )
             ),
             div(class = "flashcard-container",
                 tags$button(id = "flip", class = "flashcard-btn action-button", uiOutput("card_content"))
             ),
             div(class = "btn-group-container",
                 actionButton("wrong", "❌ 不會 / 不熟", class = "btn-danger status-btn"),
                 actionButton("good", "✅ 會了", class = "btn-success status-btn")
             ),
             hr(),
             # --- 補回：重新開始按鈕 ---
             actionButton("restart", "🔄 重新開始本輪", class = "btn-default btn-block"),
             h4(textOutput("progress"), style="text-align:center; margin-top: 20px; color: #888;")
    ),
    
    tabPanel("錯題管理與下載",
             br(),
             wellPanel(
               h4("💾 儲存今日進度"),
               p("建議練習完後下載此檔案。隔天回來練習時，先上傳題庫，再上傳此檔案即可繼續。"),
               downloadButton("download_wrong", "下載目前錯題集 (.csv)", class = "btn-primary")
             ),
             hr(),
             h4("📝 目前錯題清單"),
             DTOutput("wrong_table")
    ),
    
    tabPanel("錯題複習模式",
             br(),
             div(class = "flashcard-container",
                 tags$button(id = "flip2", class = "flashcard-btn action-button", uiOutput("review_card_content"))
             ),
             div(class = "btn-group-container",
                 actionButton("next_w", "保留，下一個", class = "btn-warning status-btn"),
                 actionButton("good2", "移除，會了", class = "btn-success status-btn")
             ),
             hr(),
             actionButton("restart_review", "🚀 開始複習錯題", class = "btn-lg btn-block btn-primary"),
             h4(textOutput("review_progress"), style="text-align:center; margin-top: 20px; color: #888;")
    ),
    
    tabPanel("歷史數據分析",
             br(),
             h4("📊 題目練習次數統計", style="text-align:center;"),
             DTOutput("history_table")
    )
  )
)

# ====== 4. Server 邏輯 ======
server <- function(input, output, session) {
  
  all_cards <- reactiveVal(NULL)
  wrong_db <- reactiveVal(data.frame(id=integer(), front=character(), back=character(), date_added=character(), stringsAsFactors=FALSE))
  
  order <- reactiveVal(NULL)
  index <- reactiveVal(1)
  show_answer <- reactiveVal(FALSE)
  
  review_order <- reactiveVal(NULL)
  review_index <- reactiveVal(1)
  show_answer2 <- reactiveVal(FALSE)
  
  # 統計更新函數
  update_stats <- function(target_id, is_wrong) {
    df <- all_cards()
    if(is.null(df)) return()
    idx <- which(df$id == target_id)
    if(length(idx) > 0) {
      df$count_total[idx] <- (df$count_total[idx] %||% 0) + 1
      if(is_wrong) df$count_wrong[idx] <- (df$count_wrong[idx] %||% 0) + 1
      all_cards(df)
    }
  }
  
  # 1. 處理新題庫上傳
  observeEvent(input$upload_file, {
    req(input$upload_file)
    raw <- read_excel(input$upload_file$datapath)
    smart_split <- function(x) {
      x <- as.character(x); x <- gsub("\r\n|\n", "<br>", x)
      target_symbols <- "➢|◼|□|✅|●|○|•|❑|▲|▼|※|◆|⚫|✓"
      x <- gsub(paste0("(?=", target_symbols, ")"), "<br>", x, perl=TRUE)
      x <- gsub("(<br>\\s*)+", "<br>", x); x <- gsub("^<br>|<br>$", "", x)
      return(x)
    }
    df <- data.frame(
      id = 1:nrow(raw), 
      front = smart_split(raw[[1]]), 
      back = smart_split(raw[[2]]), 
      count_total = 0, 
      count_wrong = 0, 
      stringsAsFactors = FALSE
    )
    all_cards(df); order(resample(df$id)); index(1); show_answer(FALSE)
  })
  
  # 2. 處理舊錯題檔讀取
  observeEvent(input$load_wrong, {
    req(input$load_wrong)
    old_data <- readRDS(input$load_wrong$datapath)
    wrong_db(old_data)
    showNotification("已同步舊的錯題紀錄！", type = "message")
  })
  
  # 3. 測驗按鈕邏輯
  process_action <- function(is_correct) {
    req(all_cards(), order())
    curr_id <- order()[index()]
    
    update_stats(curr_id, !is_correct)
    
    if (!is_correct) {
      curr_row <- all_cards()[all_cards()$id == curr_id, ]
      current_wrong <- wrong_db()
      if (!(curr_row$front %in% current_wrong$front)) {
        new_entry <- data.frame(
          id = curr_id, front = curr_row$front, back = curr_row$back, 
          date_added = as.character(Sys.Date()), stringsAsFactors = FALSE
        )
        wrong_db(rbind(current_wrong, new_entry))
      }
    }
    index(index() + 1); show_answer(FALSE)
  }
  
  observeEvent(input$wrong, { process_action(FALSE) })
  observeEvent(input$good, { process_action(TRUE) })
  observeEvent(input$flip, { show_answer(!show_answer()) })
  
  # --- 補回：重新開始邏輯 ---
  observeEvent(input$restart, {
    if(!is.null(all_cards())) {
      order(resample(all_cards()$id))
      index(1)
      show_answer(FALSE)
      showNotification("已重新洗牌開始新的一輪", type = "message")
    }
  })
  
  # 4. 下載功能
  #output$download_wrong <- downloadHandler(
  #  filename = function() { paste0("my_wrong_collection_", Sys.Date(), ".rds") },
  #  content = function(file) { saveRDS(wrong_db(), file) }
  #)
  #output$download_wrong <- downloadHandler(
  #  filename = function() {
  #    # 確保檔名沒有特殊字元，並加上時間戳
  #    paste0("wrong_set_", format(Sys.time(), "%Y%m%d_%H%M"), ".csv")
   # },
   # content = function(file) {
  #    # 強制要求資料必須存在
  #    data <- req(wrong_db())
  #    
  #    # 寫入檔案並明確指定編碼
  #    write.csv(data, file, row.names = FALSE, fileEncoding = "UTF-8")
  #  }
  #)
  # 4. 下載功能 (Shinylive 穩定優化版)
  output$download_wrong <- downloadHandler(
    filename = function() {
      # 1. 檔名絕對不要有空格或特殊符號，純英文與底線最安全
      paste0("wrong_collection_", format(Sys.Date(), "%Y%m%d"), ".csv")
    },
    content = function(file) {
      # 2. 獲取資料並確保不為空
      data_to_save <- wrong_db()
      req(nrow(data_to_save) > 0)
      
      # 3. 在 Shinylive 虛擬環境中，我們改用最保險的 csv 輸出
      # 加入 tryCatch 避免虛擬寫入權限出錯
      tryCatch({
        # 使用 UTF-8 編碼
        write.csv(data_to_save, file, row.names = FALSE, fileEncoding = "UTF-8")
      }, error = function(e) {
        showNotification("檔案生成失敗，請再試一次", type = "error")
      })
    }
  )
  
  # 5. UI 渲染
  output$card_content <- renderUI({
    df <- all_cards(); ord <- order(); idx <- index()
    if (is.null(df)) return(div(class="inner-content", style="text-align:center;", "請先點擊上方載入 Excel 題庫"))
    if (idx > length(ord)) return(div(class="inner-content", style="text-align:center;color:green;", "🎉 恭喜！本輪題庫已練習完畢。"))
    
    row <- df[df$id == ord[idx], ]
    txt <- if(!show_answer()) row$front else row$back
    tagList(div(class="card-status-hint", if(!show_answer()) "QUESTION (點擊卡片翻面)" else "ANSWER"),
            div(class="card-content-wrapper", div(class="inner-content", HTML(txt))))
  })
  
  # 6. 複習模式
  observeEvent(input$restart_review, {
    req(nrow(wrong_db()) > 0)
    review_order(resample(1:nrow(wrong_db())))
    review_index(1); show_answer2(FALSE)
  })
  
  output$review_card_content <- renderUI({
    df <- wrong_db(); ord <- review_order(); idx <- review_index()
    if (is.null(ord) || idx > length(ord)) return(div(class="inner-content", style="text-align:center;", "點擊下方按鈕開始複習您的錯題"))
    row <- df[ord[idx], ]
    txt <- if(!show_answer2()) row$front else row$back
    tagList(div(class="card-status-hint", if(!show_answer2()) "QUESTION (複習中)" else "ANSWER (複習中)"),
            div(class="card-content-wrapper", div(class="inner-content", style="color:#d9534f;", HTML(txt))))
  })
  
  observeEvent(input$flip2, { show_answer2(!show_answer2()) })
  observeEvent(input$next_w, { review_index(review_index() + 1); show_answer2(FALSE) })
  observeEvent(input$good2, {
    idx_in_db <- review_order()[review_index()]
    new_db <- wrong_db()[-idx_in_db, ]
    wrong_db(new_db)
    if (nrow(new_db) > 0) review_order(resample(1:nrow(new_db))) else review_order(NULL)
    show_answer2(FALSE)
  })
  
  output$wrong_table <- renderDT({ datatable(wrong_db()[, c("date_added", "front")], colnames = c("紀錄日期", "題目內容")) })
  
  output$history_table <- renderDT({
    req(all_cards())
    datatable(
      all_cards()[, c("front", "count_total", "count_wrong")],
      colnames = c("題目內容", "練習總次數", "出錯次數"),
      options = list(pageLength = 10, order = list(list(2, 'desc'))),
      escape = FALSE
    )
  })
  
  output$progress <- renderText({ if(is.null(order())) "" else paste0("當前題庫進度：", min(index(), length(order())), " / ", length(order())) })
  output$review_progress <- renderText({ paste0("待複習總數：", nrow(wrong_db())) })
}

shinyApp(ui, server)

